changeSet.sql:
CREATE TABLE gdpr_article
(
	id serial,
	organization_id integer DEFAULT NULL,
	chapter_id integer DEFAULT NULL,
	section_id integer DEFAULT NULL,
	article_number integer DEFAULT NULL,
	reference_number character varying (8) DEFAULT NULL,
	name character varying (127) NOT NULL,
	description text DEFAULT NULL,
	CONSTRAINT pk_gdpr_article PRIMARY KEY (id)
	, CONSTRAINT fk_gdpr_article_to_organization FOREIGN KEY (organization_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
	, CONSTRAINT fk_gdpr_article_to_chapter FOREIGN KEY (chapter_id) REFERENCES gdpr_article_chapter (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
	, CONSTRAINT fk_gdpr_article_to_section FOREIGN KEY (section_id) REFERENCES gdpr_article_chapter_section (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
);
CREATE INDEX i_gdpr_article_organization_id ON gdpr_article (organization_id);
CREATE INDEX i_gdpr_article_chapter_id ON gdpr_article (chapter_id);
CREATE INDEX i_gdpr_article_section_id ON gdpr_article (section_id);
CREATE INDEX i_gdpr_article_name ON gdpr_article (name);
